// Daily "Guess the Mascot" poster.
// Triggered once/day by an external cron (GitHub Actions) hitting:
//   /api/games/mascot?key=GAMES_SECRET
// Posts today's round, and closes/reveals yesterday's round.

const BOT_TOKEN   = process.env.DISCORD_BOT_TOKEN;
const CHANNEL_ID  = process.env.GAMES_CHANNEL_ID;
const GAMES_SECRET= process.env.GAMES_SECRET;
const SB_URL      = process.env.SUPABASE_URL;          // https://<ref>.supabase.co
const SB_KEY      = process.env.SUPABASE_SERVICE_KEY;  // service_role key (server-side only)

const API = "https://discord.com/api/v10";
const HJ  = { Authorization: `Bot ${BOT_TOKEN}`, "Content-Type": "application/json" };

// --- tiny Supabase REST helpers (PostgREST) ---
const sb = (path, init = {}) =>
  fetch(`${SB_URL}/rest/v1/${path}`, {
    ...init,
    headers: {
      apikey: SB_KEY,
      Authorization: `Bearer ${SB_KEY}`,
      "Content-Type": "application/json",
      ...(init.headers || {}),
    },
  });

// --- deterministic daily pick (no repeat for 140 days) ---
function seededShuffle(arr, seed) {
  const a = arr.slice();
  let s = seed >>> 0;
  const rng = () => ((s = (s * 1664525 + 1013904223) >>> 0) / 4294967296);
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(rng() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}
const SHUFFLED = seededShuffle(MASCOTS, 20262027); // fixed seed = stable order

function todayStr(tz = "America/Chicago") {
  const p = new Intl.DateTimeFormat("en-CA", { timeZone: tz, year: "numeric", month: "2-digit", day: "2-digit" }).format(new Date());
  return p; // YYYY-MM-DD
}
const dayNumber = (dateStr) => Math.floor(Date.parse(dateStr + "T00:00:00Z") / 86400000);

function pickRound(dateStr) {
  const answer = SHUFFLED[dayNumber(dateStr) % SHUFFLED.length];
  // decoys: prefer same conference, distinct nickname
  const pool = MASCOTS.filter(t => t.name !== answer.name && t.nickname !== answer.nickname);
  const sameConf = pool.filter(t => t.conf === answer.conf);
  const seed = dayNumber(dateStr) ^ 0x9e3779b9;
  const ranked = seededShuffle(sameConf.length >= 3 ? sameConf : pool, seed);
  const decoys = [];
  for (const t of ranked) {
    if (decoys.length >= 3) break;
    if (!decoys.some(d => d.nickname === t.nickname)) decoys.push(t);
  }
  while (decoys.length < 3) {
    const t = seededShuffle(pool, seed + decoys.length)[0];
    if (!decoys.some(d => d.name === t.name)) decoys.push(t);
  }
  const options = seededShuffle([answer, ...decoys], seed + 7);
  return { answer, options };
}

async function postToday(dateStr) {
  const { answer, options } = pickRound(dateStr);
  const buttons = options.map(o => ({
    type: 2, style: 1, label: o.name, custom_id: `mascot|${dateStr}|${o.name}`,
  }));
  const content =
    `🔍 **Guess the Mascot** — ${dateStr}\n` +
    `Today's mystery squad: the **${answer.nickname}** ${answer.emoji}\n` +
    `_Hint: ${answer.conf}._  Which school is this? (one guess each — answer revealed tomorrow)`;
  const payload = { content, components: [{ type: 1, components: buttons }] };
  const r = await fetch(`${API}/channels/${CHANNEL_ID}/messages`, {
    method: "POST", headers: HJ, body: JSON.stringify(payload),
  });
  if (!r.ok) return { ok: false, status: r.status, detail: await r.text() };
  const msg = await r.json();
  // record the round
  await sb("dyn_mascot_rounds", {
    method: "POST",
    headers: { Prefer: "resolution=merge-duplicates" },
    body: JSON.stringify({
      round_date: dateStr, answer: answer.name, nickname: answer.nickname,
      emoji: answer.emoji, conf: answer.conf,
      options: options.map(o => o.name), message_id: msg.id, channel_id: CHANNEL_ID,
    }),
  });
  return { ok: true, message_id: msg.id, answer: answer.name, options: options.map(o => o.name) };
}

async function closePrevious(todayDate) {
  const q = await sb(`dyn_mascot_rounds?round_date=lt.${todayDate}&order=round_date.desc&limit=1`);
  if (!q.ok) return { closed: false, reason: "query failed" };
  const rows = await q.json();
  if (!rows.length) return { closed: false, reason: "no previous round" };
  const prev = rows[0];
  if (!prev.message_id) return { closed: false, reason: "no message id" };
  const g = await sb(`dyn_mascot_guesses?round_date=eq.${prev.round_date}&correct=eq.true&select=username`);
  const winners = g.ok ? await g.json() : [];
  const names = winners.map(w => w.username).filter(Boolean);
  const revealed =
    `🔍 **Guess the Mascot** — ${prev.round_date}  ·  ✅ Answer: **${prev.answer}** (${prev.nickname}) ${prev.emoji || ""}\n` +
    (names.length ? `Nailed it: ${names.join(", ")}` : `Nobody got this one!`);
  await fetch(`${API}/channels/${prev.channel_id}/messages/${prev.message_id}`, {
    method: "PATCH", headers: HJ, body: JSON.stringify({ content: revealed, components: [] }),
  });
  return { closed: true, date: prev.round_date, winners: names.length };
}

export default async function handler(req, res) {
  const url = new URL(req.url, "http://x");
  if (!GAMES_SECRET || url.searchParams.get("key") !== GAMES_SECRET) {
    res.status(401).json({ error: "bad key" }); return;
  }
  try {
    const dateStr = url.searchParams.get("date") || todayStr();
    const closed = await closePrevious(dateStr);
    const posted = await postToday(dateStr);
    res.status(200).json({ ok: true, date: dateStr, closed, posted });
  } catch (e) {
    res.status(500).json({ error: String(e) });
  }
}
